noncompliant:
class C final {
protected: // Noncompliant: protected is pointless in final class
    void fun();
    int value;
};

class Database final {
protected: // Noncompliant: no derived classes possible
    void connect();
    std::string connectionString;
};

compliant:
class C final {
private: // Compliant: use private instead
    void fun();
    int value;
};

class Database final {
private: // Compliant: clear access control
    void connect();
    std::string connectionString;
public:
    void initialize(); // public interface
};
